import React, { useState, useEffect, useMemo } from "react";
import { Link } from "react-router-dom";
import { MainLayout } from "../../layouts";
import { ROUTES } from "../../constants";
import "./HomePage.css";
import { useLanguage } from "../../translet/LanguageContext";

// Import animation hooks
import {
  useScrollAnimation,
  useStaggeredAnimation,
  useCounter,
  useMotionPreferences,
} from "../../hooks/useScrollAnimation";

// Import avatar images
import minhAnhAvatar from "../../assets/images/avatar/minhanh.png";
import namAvatar from "../../assets/images/avatar/nam.png";
import huongAvatar from "../../assets/images/avatar/huonng.png";

// Import company logos
import samsungLogo from "../../assets/images/company/amazon.png";
import ministryLogo from "../../assets/images/company/fpt.png";
import vinmecLogo from "../../assets/images/company/Family Caregiver Alliance.png";

const HomePage = () => {
  const { lang, t: translate } = useLanguage();
  const [currentTextIndex, setCurrentTextIndex] = useState(0);

  // Animation refs
  const heroRef = useScrollAnimation("animate-on-scroll");
  const statsRef = useStaggeredAnimation(200);
  const featuresRef = useStaggeredAnimation(150);
  const jobsRef = useScrollAnimation("slide-in-left");
  const testimonialsRef = useScrollAnimation("slide-in-right");

  // Respect motion preferences for accessibility
  useMotionPreferences();

  // Counter refs for stats
  const counter1 = useCounter(50000, 2000);
  const counter2 = useCounter(25000, 2000);
  const counter3 = useCounter(5000, 2000);
  const counter4 = useCounter(98, 2000);

  // Multi-language content - wrapped in useMemo to fix dependency warning
  // Shared featured jobs data (language-independent)
  const sharedFeaturedJobs = useMemo(
    () => [
      {
        id: 1,
        title: "English-Japanese Interpreter",
        company: "Samsung Electronics",
        companyLogo: samsungLogo,
        location: "Ho Chi Minh City",
        salary: "$1,200-1,600",
        type: "Full-time",
        urgent: true,
        skills: ["English", "Japanese", "Technology"],
      },
      {
        id: 2,
        title: "International Conference Interpreter",
        company: "Ministry of Foreign Affairs",
        companyLogo: ministryLogo,
        location: "Hanoi",
        salary: "$1,400-2,200",
        type: "Project-based",
        urgent: false,
        skills: ["English", "French", "Diplomacy"],
      },
      {
        id: 3,
        title: "Medical Interpreter - General Hospital",
        company: "Vinmec Hospital",
        companyLogo: vinmecLogo,
        location: "Ho Chi Minh City",
        salary: "$900-1,400",
        type: "Part-time",
        urgent: false,
        skills: ["English", "Medicine", "Healthcare"],
      },
      {
        id: 4,
        title: "On-site Factory Interpreter",
        company: "Samsung Electronics",
        companyLogo: samsungLogo,
        location: "Bac Ninh",
        salary: "$750-1,050",
        type: "Shift-based",
        urgent: true,
        skills: ["Korean", "Manufacturing", "Reporting"],
      },
      {
        id: 5,
        title: "Legal Contract Interpreter",
        company: "Ministry of Foreign Affairs",
        companyLogo: ministryLogo,
        location: "Hanoi",
        salary: "$1,800-2,700",
        type: "Full-time",
        urgent: false,
        skills: ["English", "Law", "Contracts"],
      },
      {
        id: 6,
        title: "Medical Documentation Translator",
        company: "Vinmec Hospital",
        companyLogo: vinmecLogo,
        location: "Da Nang",
        salary: "$950-1,450",
        type: "Remote",
        urgent: false,
        skills: ["English", "Medical", "Translation"],
      },
      {
        id: 7,
        title: "Internal Training Interpreter",
        company: "Samsung Electronics",
        companyLogo: samsungLogo,
        location: "Thai Nguyen",
        salary: "$950-1,350",
        type: "Full-time",
        urgent: false,
        skills: ["English", "Training", "Note-taking"],
      },
      {
        id: 8,
        title: "Logistics & Supply Chain Interpreter",
        company: "Ministry of Foreign Affairs",
        companyLogo: ministryLogo,
        location: "Hai Phong",
        salary: "$1,150-1,550",
        type: "Project-based",
        urgent: false,
        skills: ["Chinese", "Logistics", "Supply Chain"],
      },
      {
        id: 9,
        title: "Medical Symposium Interpreter",
        company: "Vinmec Hospital",
        companyLogo: vinmecLogo,
        location: "Ho Chi Minh City",
        salary: "$1,600-2,000",
        type: "Event-based",
        urgent: true,
        skills: ["English", "Conference", "Medical"],
      },
    ],
    []
  );

  const content = useMemo(
    () => ({
      vi: {
        heroTitle: "Kết Nối",
        heroSubtitle: "Tài Năng & Cơ Hội",
        heroDescription:
          "Nền tảng tìm kiếm việc làm và dịch thuật hàng đầu Việt Nam",
        stats: [
          { number: "50,000+", label: "Việc làm" },
          { number: "25,000+", label: "Ứng viên" },
          { number: "5,000+", label: "Công ty" },
          { number: "98%", label: "Thành công" },
        ],
        features: [
          {
            icon: "🌐",
            title: "Dịch thuật chuyên nghiệp",
            desc: "Kết nối với phiên dịch viên uy tín",
          },
          {
            icon: "⚡",
            title: "Ứng tuyển nhanh",
            desc: "Chỉ với 1 click",
          },
          {
            icon: "💼",
            title: "Cơ hội toàn cầu",
            desc: "Việc làm trong và ngoài nước",
          },
        ],
        animatedTexts: [
          "Phiên dịch viên chuyên nghiệp",
          "Cơ hội việc làm hấp dẫn",
          "Kết nối toàn cầu",
          "Sự nghiệp trong tầm tay",
        ],
        featuredJobs: {
          title: "Việc làm phiên dịch nổi bật",
          subtitle: "Cơ hội việc làm hấp dẫn dành cho phiên dịch viên",
          viewAll: "Xem tất cả",
          apply: "Ứng tuyển",
          save: "Lưu",
          jobs: sharedFeaturedJobs,
        },
        testimonials: {
          title: "Khách hàng nói gì về chúng tôi",
          subtitle: "Những phản hồi tích cực từ cộng đồng người dùng",
          reviews: [
            {
              id: 1,
              name: "Nguyễn Minh Anh",
              role: "Phiên dịch viên",
              avatar: minhAnhAvatar,
              rating: 5,
              content:
                "G-Bridge đã giúp tôi tìm được nhiều cơ hội việc làm tuyệt vời. Nền tảng rất dễ sử dụng và hỗ trợ khách hàng tận tình.",
            },
            {
              id: 2,
              name: "Trần Văn Nam",
              role: "HR Manager - FPT Software",
              avatar: namAvatar,
              rating: 5,
              content:
                "Chúng tôi đã tuyển được nhiều phiên dịch viên chất lượng qua G-Bridge. Quy trình tuyển dụng nhanh chóng và hiệu quả.",
            },
            {
              id: 3,
              name: "Lê Thị Hương",
              role: "Freelance Translator",
              avatar: huongAvatar,
              rating: 4,
              content:
                "Giao diện đẹp, dễ sử dụng. Tôi đã tìm được nhiều dự án phù hợp với kỹ năng của mình.",
            },
          ],
        },
      },
      en: {
        heroTitle: "Connect",
        heroSubtitle: "Talent & Opportunities",
        heroDescription:
          "Leading job search and translation platform in Vietnam",
        stats: [
          { number: "50,000+", label: "Jobs" },
          { number: "25,000+", label: "Candidates" },
          { number: "5,000+", label: "Companies" },
          { number: "98%", label: "Success Rate" },
        ],
        features: [
          {
            icon: "🌐",
            title: "Professional Translation",
            desc: "Connect with trusted interpreters",
          },
          {
            icon: "⚡",
            title: "Quick Apply",
            desc: "Apply with just 1 click",
          },
          {
            icon: "💼",
            title: "Global Opportunities",
            desc: "Jobs worldwide",
          },
        ],
        animatedTexts: [
          "Professional Interpreters",
          "Attractive Job Opportunities",
          "Global Connections",
          "Career Within Reach",
        ],
        featuredJobs: {
          title: "Featured Interpreter Jobs",
          subtitle: "Great opportunities for professional interpreters",
          viewAll: "View All",
          apply: "Apply",
          save: "Save",
          jobs: sharedFeaturedJobs,
        },
        testimonials: {
          title: "What Our Users Say",
          subtitle: "Positive feedback from our user community",
          reviews: [
            {
              id: 1,
              name: "Nguyen Minh Anh",
              role: "Interpreter",
              avatar: minhAnhAvatar,
              rating: 5,
              content:
                "G-Bridge helped me find many great job opportunities. The platform is very user-friendly and customer support is excellent.",
            },
            {
              id: 2,
              name: "Tran Van Nam",
              role: "HR Manager - FPT Software",
              avatar: namAvatar,
              rating: 5,
              content:
                "We have recruited many quality interpreters through G-Bridge. The recruitment process is fast and efficient.",
            },
            {
              id: 3,
              name: "Le Thi Huong",
              role: "Freelance Translator",
              avatar: huongAvatar,
              rating: 4,
              content:
                "Beautiful interface, easy to use. I found many projects that match my skills.",
            },
          ],
        },
      },
    }),
    [sharedFeaturedJobs]
  );

  // Animated text cycling based on dictionary animatedTexts
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentTextIndex((prevIndex) => {
        const arr = translate("home.animatedTexts", []);
        return arr.length ? (prevIndex + 1) % arr.length : 0;
      });
    }, 3000);

    return () => clearInterval(interval);
  }, [lang, translate]);
  // Featured jobs slider state (group-based to avoid blank slides at wider breakpoints)
  const [groupIndex, setGroupIndex] = useState(0);
  const [isJobPaused, setIsJobPaused] = useState(false);
  const [visibleCount, setVisibleCount] = useState(1);

  const jobs = content.en.featuredJobs.jobs; // jobs data language-independent; reuse existing array

  // Determine how many slides are visible based on window width (sync with CSS breakpoints)
  useEffect(() => {
    const computeVisible = () => {
      const w = window.innerWidth;
      if (w >= 1400) return 3;
      if (w >= 900) return 2;
      return 1;
    };
    const handleResize = () => {
      setVisibleCount((prev) => {
        const next = computeVisible();
        if (next !== prev) {
          // Re-clamp group index if out of range after resize
          const maxGroups = Math.ceil(jobs.length / next);
          setGroupIndex((g) => (g >= maxGroups ? 0 : g));
        }
        return next;
      });
    };
    setVisibleCount(computeVisible());
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, [jobs.length]);

  const totalGroups = useMemo(
    () => Math.ceil(jobs.length / visibleCount),
    [jobs.length, visibleCount]
  );

  // Auto-advance groups (not individual slides) to prevent blank trailing space
  useEffect(() => {
    if (isJobPaused || totalGroups <= 1) return;
    const interval = setInterval(() => {
      setGroupIndex((prev) => (prev + 1) % totalGroups);
    }, 3000);
    return () => clearInterval(interval);
  }, [isJobPaused, totalGroups]);

  // Reset group on language change (jobs array label change) or visible count change
  useEffect(() => {
    setGroupIndex(0);
  }, [lang, visibleCount]);

  return (
    <MainLayout>
      <div className="modern-homepage">
        {/* Animated Background */}
        <div className="hero-background">
          <div className="background-animation">
            <div className="floating-shape shape-1 float-animation"></div>
            <div className="floating-shape shape-2 float-animation"></div>
            <div className="floating-shape shape-3 float-animation"></div>
            <div className="floating-shape shape-4 float-animation"></div>
            <div className="floating-shape shape-5 float-animation"></div>
          </div>
          <div className="gradient-overlay"></div>
          <div className="particle-container">
            {[...Array(20)].map((_, i) => (
              <div
                key={i}
                className={`particle particle-${i + 1} float-animation`}
              ></div>
            ))}
          </div>
        </div>

        {/* Hero Section */}
        <section className="hero-section" ref={heroRef}>
          <div className="hero-container">
            <div className="hero-content">
              {/* Main Title */}
              <div className="hero-title-wrapper">
                <h1 className="hero-title animated-gradient-text">
                  <span className="title-main">{t.heroTitle}</span>
                  <span className="title-accent">{t.heroSubtitle}</span>
                </h1>
                <div className="animated-text-container">
                  <span className="animated-text">
                    {t.animatedTexts[currentTextIndex]}
                  </span>
                </div>
              </div>

              {/* Description */}
              <p className="hero-description">{t.heroDescription}</p>

              {/* Quick Action Buttons */}
              <div className="hero-actions">
                <Link
                  to="/find-job"
                  className="action-button primary ripple-effect"
                >
                  <i className="fas fa-briefcase"></i>
                  <span>
                    {currentLanguage === "vi" ? "Tìm việc làm" : "Find Jobs"}
                  </span>
                </Link>
                <Link
                  to="/find-interpreter"
                  className="action-button secondary ripple-effect"
                >
                  <i className="fas fa-language"></i>
                  <span>
                    {currentLanguage === "vi"
                      ? "Tìm phiên dịch"
                      : "Find Interpreter"}
                  </span>
                </Link>
                <Link
                  to="/post-job"
                  className="action-button outlined ripple-effect"
                >
                  <i className="fas fa-plus"></i>
                  <span>
                    {currentLanguage === "vi" ? "Đăng tuyển dụng" : "Post Job"}
                  </span>
                </Link>
              </div>
            </div>

            {/* Hero Stats */}
            <div className="hero-stats" ref={statsRef}>
              {t.stats.map((stat, index) => (
                <div key={index} className="stat-item hover-lift">
                  <div
                    className="stat-number"
                    ref={
                      index === 0
                        ? counter1
                        : index === 1
                        ? counter2
                        : index === 2
                        ? counter3
                        : counter4
                    }
                  >
                    {stat.number}
                  </div>
                  <div className="stat-label">{stat.label}</div>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* Features Section */}
        <section className="features-section">
          <div className="features-container">
            <div className="section-header">
              <h2 className="section-title animated-gradient-text">
                {currentLanguage === "vi"
                  ? "Tại sao chọn G-Bridge?"
                  : "Why Choose G-Bridge?"}
              </h2>
              <p className="section-subtitle">
                {currentLanguage === "vi"
                  ? "Nền tảng công nghệ hiện đại với các tính năng vượt trội"
                  : "Modern technology platform with superior features"}
              </p>
            </div>

            <div className="features-grid" ref={featuresRef}>
              {t.features.map((feature, index) => (
                <div
                  key={index}
                  className="feature-card hover-lift magnetic-hover"
                >
                  <div className="feature-icon">
                    <span>{feature.icon}</span>
                  </div>
                  <h3 className="feature-title">{feature.title}</h3>
                  <p className="feature-description">{feature.desc}</p>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* Featured Jobs Section */}
        <section className="featured-jobs-section" ref={jobsRef}>
          <div className="featured-jobs-container">
            <div className="section-header">
              <h2 className="section-title animated-gradient-text">
                {t.featuredJobs.title}
              </h2>
              <p className="section-subtitle">{t.featuredJobs.subtitle}</p>
            </div>

            <div
              className="jobs-slider"
              onMouseEnter={() => setIsJobPaused(true)}
              onMouseLeave={() => setIsJobPaused(false)}
            >
              <div
                className="jobs-track"
                style={{ transform: `translateX(-${groupIndex * 100}%)` }}
              >
                {jobs.map((job, idx) => (
                  <div
                    className="job-slide"
                    key={job.id}
                    aria-hidden={Math.floor(idx / visibleCount) !== groupIndex}
                  >
                    <div className="job-card hover-lift magnetic-hover breathing-effect">
                      {job.urgent && <div className="urgent-badge">URGENT</div>}
                      <div className="job-header">
                        <h3 className="job-title">{job.title}</h3>
                        <div className="job-actions">
                          <button
                            className="action-btn save-btn"
                            title={t.featuredJobs.save}
                          >
                            <i className="fas fa-bookmark"></i>
                          </button>
                        </div>
                      </div>
                      <div className="job-company">
                        <div className="company-logo">
                          <img src={job.companyLogo} alt={job.company} />
                        </div>
                        <span>{job.company}</span>
                      </div>
                      <div className="job-details">
                        <div className="job-detail">
                          <i className="fas fa-map-marker-alt"></i>
                          <span>{job.location}</span>
                        </div>
                        <div className="job-detail">
                          <i className="fas fa-dollar-sign"></i>
                          <span>{job.salary}</span>
                        </div>
                        <div className="job-detail">
                          <i className="fas fa-clock"></i>
                          <span>{job.type}</span>
                        </div>
                      </div>
                      <div className="job-skills">
                        {job.skills.map((skill, index) => (
                          <span key={index} className="skill-tag">
                            {skill}
                          </span>
                        ))}
                      </div>
                      <button className="apply-btn ripple-effect">
                        <span>{t.featuredJobs.apply}</span>
                        <i className="fas fa-arrow-right"></i>
                      </button>
                    </div>
                  </div>
                ))}
              </div>
              <div
                className="jobs-dots"
                role="tablist"
                aria-label="Featured jobs"
              >
                {Array.from({ length: totalGroups }).map((_, idx) => (
                  <button
                    key={idx}
                    className={`jobs-dot ${groupIndex === idx ? "active" : ""}`}
                    onClick={() => setGroupIndex(idx)}
                    aria-label={`Go to job group ${idx + 1}`}
                    aria-selected={groupIndex === idx}
                    role="tab"
                  />
                ))}
              </div>
              <button
                type="button"
                className="jobs-nav prev"
                onClick={() =>
                  setGroupIndex(
                    (prev) => (prev - 1 + totalGroups) % totalGroups
                  )
                }
                aria-label="Previous job"
              >
                <i className="fas fa-chevron-left" />
              </button>
              <button
                type="button"
                className="jobs-nav next"
                onClick={() =>
                  setGroupIndex((prev) => (prev + 1) % totalGroups)
                }
                aria-label="Next job"
              >
                <i className="fas fa-chevron-right" />
              </button>
            </div>

            <div className="view-all-container">
              <Link to="/jobs" className="view-all-btn">
                {t.featuredJobs.viewAll}
                <i className="fas fa-arrow-right"></i>
              </Link>
            </div>
          </div>
        </section>

        {/* Testimonials Section */}
        <section className="testimonials-section" ref={testimonialsRef}>
          <div className="testimonials-container">
            <div className="section-header">
              <h2 className="section-title animated-gradient-text">
                {t.testimonials.title}
              </h2>
              <p className="section-subtitle">{t.testimonials.subtitle}</p>
            </div>

            <div className="testimonials-grid">
              {t.testimonials.reviews.map((review) => (
                <div
                  key={review.id}
                  className="testimonial-card hover-lift tilt-effect"
                >
                  <div className="testimonial-content">
                    <div className="quote-icon">
                      <i className="fas fa-quote-left"></i>
                    </div>
                    <p className="testimonial-text">{review.content}</p>
                    <div className="rating">
                      {[...Array(5)].map((_, i) => (
                        <i
                          key={i}
                          className={`fas fa-star ${
                            i < review.rating ? "active" : ""
                          }`}
                        ></i>
                      ))}
                    </div>
                  </div>

                  <div className="testimonial-author">
                    <div className="author-avatar">
                      <img src={review.avatar} alt={review.name} />
                    </div>
                    <div className="author-info">
                      <h4 className="author-name">{review.name}</h4>
                      <p className="author-role">{review.role}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* CTA Section */}
        <section className="cta-section">
          <div className="cta-container">
            <div className="cta-content">
              <h2 className="cta-title">
                {currentLanguage === "vi"
                  ? "Bắt đầu hành trình sự nghiệp của bạn ngay hôm nay!"
                  : "Start your career journey today!"}
              </h2>
              <p className="cta-description">
                {currentLanguage === "vi"
                  ? "Tham gia cộng đồng hàng nghìn ứng viên và nhà tuyển dụng"
                  : "Join the community of thousands of candidates and recruiters"}
              </p>
              <div className="cta-buttons">
                <Link to={ROUTES.REGISTER} className="cta-button primary">
                  {currentLanguage === "vi" ? "Đăng ký ngay" : "Register Now"}
                </Link>
                <Link to={ROUTES.LOGIN} className="cta-button secondary">
                  {currentLanguage === "vi" ? "Đăng nhập" : "Login"}
                </Link>
              </div>
            </div>
          </div>
        </section>
      </div>
    </MainLayout>
  );
};

export default HomePage;
